module RefModule(
    input clk,
    input reset,
    input a,
    input b,
    input sel_b1,
    output reg [6:0] prbs
);reg [6:0] obf_prbs_reg;
wire mux_out;
reg mux_sel;

assign mux_out = sel_b1 ? b : a;

always @(posedge clk, negedge reset) begin
    if (!reset) begin
        obf_prbs_reg <= 7'b0000000;
        mux_sel <= 1'b0;
    end else begin
        obf_prbs_reg <= {obf_prbs_reg[5:0], obf_prbs_reg[6] ^ mux_out ^ obf_prbs_reg[0]};
        mux_sel <= ~mux_sel;
    end
end

always @(posedge clk, negedge reset) begin
    if (!reset) begin
        prbs <= 7'b0000000;
    end else begin
        prbs <= {obf_prbs_reg[6], obf_prbs_reg[5] ^ obf_prbs_reg[6], obf_prbs_reg[4] ^ obf_prbs_reg[6], obf_prbs_reg[3] ^ obf_prbs_reg[6], obf_prbs_reg[2] ^ obf_prbs_reg[6], obf_prbs_reg[1] ^ obf_prbs_reg[6], obf_prbs_reg[0] ^ obf_prbs_reg[6]};
    end
end

endmodule
